import tkinter as tkfrom tkinter import ttk, messageboximport matplotlib.pyplot as pltfrom matplotlib.backends.backend_tkagg import FigureCanvasTkAgg#Default-----------------------------------------------------------------------prize_pool = 350places_payed = 15first_percentage = 0.3#these will be used as a baseline for the distributions. Change later#quick % calculator for working out a fixed 1st place as a percentage----------def as_percent(target_amount, prizepool = prize_pool):    as_p = target_amount/prize_pool        return as_p#Distribution functions--------------------------------------------------------def distribution_1(prizes = prize_pool,players = places_payed,first = first_percentage,slope=0.5):    distribution = []    payout = first        for i in range (0, players):        place = (f"{i+1}",prizes * payout)        distribution.append(place)        payout = payout*slope            return distributiondef distribution_2(prizes = prize_pool, players = places_payed, first = first_percentage):    distribution =[]    total = prizes        for i in range(0,players):        amount_won = total * first        distribution.append((f"{i+1}", amount_won))        total = total - amount_won        return distributiondef distribution_3(prizes = prize_pool, players = places_payed, first = first_percentage, slope = 0.05):    distribution = []    winning_percentage = first_percentage        for i in range(0, players):        amount_won = prizes*winning_percentage        distribution.append((f"{i+1}", amount_won))        winning_percentage = winning_percentage - slope        return distributiondef distribution_4(prizes = prize_pool, players = places_payed, first = first_percentage):    distribution = []    winning_percentage = first_percentage    slope = 1/players        for i in range(0, players):        amount_won = prizes*winning_percentage        distribution.append((f"{i+1}", amount_won))        winning_percentage = winning_percentage - slope        return distribution#GUI (ft ChatGPT)--------------------------------------------------------------class PrizePoolApp:    def __init__(self, root):        self.root = root        self.root.title("Prize Pool Visualiser")        self.root.geometry("1150x750")        # Control frame        control_frame = ttk.Frame(root, padding=10)        control_frame.pack(side=tk.LEFT, fill=tk.Y)        ttk.Label(control_frame, text="Prize Pool").grid(row=0, column=0, sticky="w", pady=5)        self.prize_pool_entry = ttk.Entry(control_frame)        self.prize_pool_entry.insert(0, str(prize_pool))        self.prize_pool_entry.grid(row=0, column=1, pady=5)        ttk.Label(control_frame, text="Places Paid").grid(row=1, column=0, sticky="w", pady=5)        self.places_paid_entry = ttk.Entry(control_frame)        self.places_paid_entry.insert(0, str(places_payed))        self.places_paid_entry.grid(row=1, column=1, pady=5)        ttk.Label(control_frame, text="1st Place %").grid(row=2, column=0, sticky="w", pady=5)        self.first_percentage_entry = ttk.Entry(control_frame)        self.first_percentage_entry.insert(0, str(first_percentage))        self.first_percentage_entry.grid(row=2, column=1, pady=5)        ttk.Label(control_frame, text="Slope").grid(row=3, column=0, sticky="w", pady=5)        self.slope_entry = ttk.Entry(control_frame)        self.slope_entry.insert(0, "0.5")        self.slope_entry.grid(row=3, column=1, pady=5)        ttk.Label(control_frame, text="Distribution Type").grid(row=4, column=0, sticky="w", pady=5)        self.dist_var = tk.StringVar(value="distribution_1")        self.dist_menu = ttk.Combobox(            control_frame,            textvariable=self.dist_var,            values=["distribution_1", "distribution_2", "distribution_3", "distribution_4"],            state="readonly"        )        self.dist_menu.grid(row=4, column=1, pady=5)        ttk.Button(control_frame, text="Generate Chart", command=self.update_chart).grid(            row=5, column=0, columnspan=2, pady=10, sticky="ew"        )        ttk.Button(control_frame, text="Clear Output", command=self.clear_output).grid(            row=6, column=0, columnspan=2, pady=5, sticky="ew"        )        # Quick percentage calculator        ttk.Separator(control_frame, orient="horizontal").grid(row=7, column=0, columnspan=2, sticky="ew", pady=15)        ttk.Label(control_frame, text="Quick Percentage Calculator").grid(            row=8, column=0, columnspan=2, sticky="w", pady=(0, 5)        )        ttk.Label(control_frame, text="Target Amount").grid(row=9, column=0, sticky="w", pady=5)        self.target_amount_entry = ttk.Entry(control_frame)        self.target_amount_entry.insert(0, "100")        self.target_amount_entry.grid(row=9, column=1, pady=5)        ttk.Button(control_frame, text="Calculate %", command=self.calculate_percentage).grid(            row=10, column=0, columnspan=2, pady=5, sticky="ew"        )        self.percentage_result_var = tk.StringVar(value="Percentage: ")        ttk.Label(control_frame, textvariable=self.percentage_result_var).grid(            row=11, column=0, columnspan=2, sticky="w", pady=5        )        # Output text        ttk.Label(control_frame, text="Payouts").grid(row=12, column=0, columnspan=2, sticky="w", pady=(15, 5))        self.output_text = tk.Text(control_frame, width=35, height=20)        self.output_text.grid(row=13, column=0, columnspan=2, pady=5)        # Chart frame        chart_frame = ttk.Frame(root, padding=10)        chart_frame.pack(side=tk.RIGHT, fill=tk.BOTH, expand=True)        self.fig, self.ax = plt.subplots(figsize=(8, 5))        self.canvas = FigureCanvasTkAgg(self.fig, master=chart_frame)        self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)        self.update_chart()    def clear_output(self):        self.output_text.delete("1.0", tk.END)        self.percentage_result_var.set("Percentage: ")    def get_inputs(self):        try:            prizes = float(self.prize_pool_entry.get())            players = int(self.places_paid_entry.get())            first = float(self.first_percentage_entry.get())            slope = float(self.slope_entry.get())            if prizes <= 0:                raise ValueError("Prize pool must be greater than 0.")            if players <= 0:                raise ValueError("Places paid must be greater than 0.")            if first < 0:                raise ValueError("1st place percentage cannot be negative.")            return prizes, players, first, slope        except ValueError as e:            messagebox.showerror("Input Error", str(e))            return None    def generate_distribution(self, prizes, players, first, slope):        dist_type = self.dist_var.get()        if dist_type == "distribution_1":            return distribution_1(prizes, players, first, slope)        elif dist_type == "distribution_2":            return distribution_2(prizes, players, first)        elif dist_type == "distribution_3":            return distribution_3(prizes, players, first, slope)        elif dist_type == "distribution_4":            return distribution_4(prizes, players, first)        else:            return []    def calculate_percentage(self):        try:            prizepool = float(self.prize_pool_entry.get())            target_amount = float(self.target_amount_entry.get())            if prizepool <= 0:                raise ValueError("Prize pool must be greater than 0.")            result = as_percent(target_amount, prizepool) * 100            self.percentage_result_var.set(f"Percentage: {result:.2f}%")        except ValueError as e:            messagebox.showerror("Calculation Error", str(e))    def update_chart(self):        inputs = self.get_inputs()        if inputs is None:            return        prizes, players, first, slope = inputs        distribution = self.generate_distribution(prizes, players, first, slope)        places = [place for place, amount in distribution]        amounts = [amount for place, amount in distribution]        self.ax.clear()        self.ax.bar(places, amounts)        self.ax.set_title("Prize Pool Distribution")        self.ax.set_xlabel("Place")        self.ax.set_ylabel("Payout")        self.ax.tick_params(axis="x", rotation=45)        self.fig.tight_layout()        self.canvas.draw()        self.output_text.delete("1.0", tk.END)        total_paid = 0        for place, amount in distribution:            self.output_text.insert(tk.END, f"Place {place}: {amount:.2f}\n")            total_paid += amount        self.output_text.insert(tk.END, f"\nTotal paid out: {total_paid:.2f}\n")        self.output_text.insert(tk.END, f"Prize pool: {prizes:.2f}\n")        self.output_text.insert(tk.END, f"Difference: {prizes - total_paid:.2f}\n")# -----------------------------# Run app# -----------------------------if __name__ == "__main__":    root = tk.Tk()    app = PrizePoolApp(root)    root.mainloop()    